var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"저기… 전 음료수 병뚜껑 이벤트에 당첨돼서 온 건데 여기 있어도 돼요?","JPN":"あの……私、ボトルキャップのイベントに当たって来ただけなんですけど、ここにいてもいいんですか？","ENG":"Um... Are you sure I can be here? I just came here because the bottle cap said I won something...","TWN":"那個…我是參加飲料瓶蓋活動中獎的，待在這裡沒問題嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"물론이지! 심사를 잘 부탁하네!","JPN":"もちろんだ！　審査をよろしく頼む！","ENG":"Of course! I'm sure you'll be a fair judge!","TWN":"當然沒問題！要麻煩你當評審囉！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"후후, 불멸의 팝핀이라 불리는 토미님에게 심사를 맡기다니 배짱도 좋군.","JPN":"ふふ、不滅のポッパーと呼ばれているトミー様に審査を任せるとは、いい度胸だぜ。","ENG":"Hah hah! You've appointed me, Tommy the Immortal Poppin, as a dance judge? That's a ballsy move.","TWN":"呵呵，算你們有種，竟敢請人稱不朽Popping的湯米來當評審！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"와! 하트베리 춤 따라 추면 500점 줄래요!","JPN":"わーい！　ハートベリーの振り付けを踊ってくれたら500点あげるのです！","ENG":"Wow! If you do the HRT Berry dance, I'll give you 500 points!","TWN":"哇！跳愛心莓果的舞就給500分！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"기회는 세 번. 세 번 중 단 한 번이라도 허드슨 님을 이기면 도전자 측의 승리입니다.","JPN":"チャンスは3回。3回のうち、1回でもハドソン様に勝利すると挑戦者側の勝ちです。","ENG":"You have 3 tries. If the challenger beats Mr. Hudson once out of all the rounds, they will be proclaimed the winners.","TWN":"一共會進行3場，只要任何一場贏過哈德森先生，就算挑戰方勝利。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"처음은 어떤 분이 도전하시겠습니까?","JPN":"最初はどなたが挑戦しますか？","ENG":"Now, who would like to challenge him first?","TWN":"哪位要先進行挑戰呢？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"앗?!","JPN":"あっ！？","ENG":"Huh?!","TWN":"啊？！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"가라, 샌님! 네가 도움이 된다는 걸 보여 줘!","JPN":"行け、ナード！　アンタが役に立つってところを見せて！","ENG":"Go, dweeb! Prove to us that you're useful!","TWN":"你上啊！去證明你是有用的！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"자, 잠깐! 최소한 안무 정도는 생각할 시간을 줘야지!","JPN":"ま、待って！　少なくとも振り付けを考える時間くらいはほしいよ！","ENG":"W-wait! At least give me some time to think about my dance routine!","TWN":"等…等一下啦！至少要給我點編舞的時間吧！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"힘내라, 우리 편!","JPN":"頑張れ、私たちのチーム！","ENG":"Go team, go!","TWN":"加油喔，我們的人！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그래도 체격은 좋으니까, 의외로 기대할 수 있지 않을까?","JPN":"でも体格はいいから、意外と期待できるんじゃないかな？","ENG":"But he does look fit, so maybe he stands a chance of winning?","TWN":"至少你身材蠻好的，說不定可以期待一下喔？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그래. 우리 중에 춤을 춰 본 사람이 있는 것도 아니고.","JPN":"たしかに。ワタシたちの中で踊ったことがある人がいるわけでもないし。","ENG":"Yeah. Plus, it's not like any of us have ever danced before.","TWN":"是啊，更何況我們之中也沒人跳過舞。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"으윽…… 어, 어쩔 수 없지.","JPN":"ううっ……し、仕方ないな。","ENG":"Ngh... Fine, I'll do it.","TWN":"呃……那好吧。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"좋아. 평소처럼 하면 돼. 할 수 있어. 일단 무대에 올라가서……","JPN":"よし。いつもどおりでいいんだ。できる。とりあえずステージに上がって……","ENG":"All right. Just act natural. You can do this! Just get up on stage and...","TWN":"好，平常心就好，我可以的，總之先站上舞台……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"무대……. 그래, 무대에 올라가야…….","JPN":"ステージ……そうだ、ステージに上がらないと……","ENG":"Stage... Yeah, just have to get up there...","TWN":"舞台……對，要站上舞台……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야? 무슨 이벤트야?","JPN":"何？　なんのイベントだ？","ENG":"Huh? Is this some sort of event?","TWN":"哇？這是什麼活動？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"라스트 헤이븐에 도전자가 나타났대!","JPN":"ラストヘイブンに挑戦者が現れたんだって！","ENG":"Someone's challenging at Last Haven!","TWN":"聽說最後的天堂有挑戰者咧？！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"저 녀석, 헤이븐 워너비잖아! 어이, 실력 좀 보여 줘!","JPN":"あいつ、ヘイブンのファンだろう！　おい、腕前を見せてくれよ！","ENG":"Hey, that guy's a Haven wannabe! Yo! Show us what you got, man!","TWN":"那傢伙根本天堂的鐵粉吧！喂，讓我們瞧瞧你的厲害吧！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"루트! 괜찮아?","JPN":"ルート！　大丈夫？","ENG":"Root! Are you okay?","TWN":"路特！你還好嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"미, 미안…… 사람이…… 사람이 너무 많아…….","JPN":"ご、ごめん……人が……人が多すぎ……","ENG":"S-sorry... But th-there's... too m-many... people...","TWN":"對…對不起……人……人好多，我……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"시선 때문에 숨이…….","JPN":"視線のせいで息が……","ENG":"I... I can't breathe...","TWN":"這麼多人看著我，我都快喘不……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"맞아. 네가 무슨 춤을 출지 다들 궁금한가 봐.","JPN":"うん。みんな、ルートがどんな風に踊るのか気になるみたい。","ENG":"Right. Everyone wants to see you dance.","TWN":"對啊，大家好像都很期待你會跳什麼舞欸。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"……어, 어?","JPN":"……え、ええ？","ENG":"H-huh...?","TWN":"……是…是嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"무서우면 나랑 같이 가자. 다시 일어나 볼래?","JPN":"怖いなら私と一緒に行こう。もう一度立ってみて？","ENG":"But if you're scared, I'll dance with you. Think you can stand up?","TWN":"你要是怕的話我和你一起吧！你可以站得起來嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"미안. 나, 가면 없이는 도저히 사람들 앞에 못 서겠어.","JPN":"ごめん。僕、仮面なしではみんなの前に立てないよ。","ENG":"Sorry. Without my mask, I don't think I'll be able to stand in front of all these people.","TWN":"對不起，沒有面具我就不敢站在眾人面前。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"시선이 너무 무서워. 눈을 보고 있으면 숨이 쉬어지지 않아.","JPN":"視線が怖すぎる。目を見てると息ができないんだ。","ENG":"The way everyone is staring at me... It's scary. With all those eyes on me I can't even breathe...","TWN":"大家的視線好可怕，看著大家的眼睛我就會喘不過氣。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"정말? 그럼 눈을 감고 하면 어때?","JPN":"本当？　じゃあ、目をつぶってやるのはどう？","ENG":"Really? Then how about we dance with our eyes closed?","TWN":"真的嗎？那乾脆把眼睛閉上吧？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"잠깐, 내가 그런 간단한 방식도 안 해 봤을 리가……","JPN":"ちょっと、そんなのとっくに……","ENG":"Huh? But there's no way that's going to w–","TWN":"等等，那麼簡單的方法我怎麼可能……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"걱정 마! 내가 안 넘어지게 지켜 줄게!","JPN":"大丈夫！　私が転ばないように守ってあげるよ！","ENG":"Don't worry! I'll make sure you don't trip and fall!","TWN":"別擔心，我會保護你，不讓你跌倒的！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"알겠어. 한번 해 볼게.","JPN":"わかった。一度やってみる。","ENG":"Okay. Let's give it a shot.","TWN":"好吧，那我就試試看。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"오, 오오…… 굉장……","JPN":"お、おお……これは……","ENG":"Oh... Ooh...! Amazing...!","TWN":"哇，哇哇……好厲害……"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"아니, 꽤 하는데! 꼭 한 마리 코모도 도마뱀 같았어! 이 토미님이 인정해 주지!","JPN":"いや、なかなかやるじゃねぇか！　まるでコモドドラゴンのようだったぞ！　このトミー様が認めてやる！","ENG":"Hey, not bad at all! It was like watching a Comodo Dragon in the wild! Tommy approves!","TWN":"哇，很強欸！好像一隻科莫多龍！湯米我認同你的舞技！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"몸이 고양이처럼 유연해요! 보미 언니에게 배우면 더 좋겠어요!","JPN":"身体が猫のように柔らかいです！　ボミから教えてもらうともっといいと思うのです！","ENG":"You're flexible like a cat! You'll be even better if you learn from Bomi!","TWN":"身體跟貓咪一樣軟欸！要是跟普美姊姊學跳舞的話，一定可以跳得更好！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"왠지 졸린 코끼리를 닮은 움직임… 합격!","JPN":"なんだか眠たい象に似てる動き……合格！","ENG":"Your movements remind me of a sleepy elephant... I approve!","TWN":"舞步很像昏昏欲睡的大象…合格！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"네. 심사위원들의 의견을 종합한 결과……","JPN":"はい。審査員の意見をまとめた結果……","ENG":"Okay, after counting all the votes from our judges...","TWN":"好的，綜合評審團的意見後，結果是……"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"만장일치로, 허드슨 님께서 승리하셨습니다.","JPN":"満場一致で、ハドソン様の勝利です。","ENG":"It's unanimous! Mr. Hudson wins!","TWN":"評審團一致同意，由哈德森先生勝出！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"크흑! 분하다! 이길 수 있을 줄 알았는데!","JPN":"くうっ！　悔しい！　勝てると思ってたのに！","ENG":"Kgh...! I thought I could win...!","TWN":"咳咳！可惡！我還以為可以贏過他！"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그 난리를 피워 놓고 어떻게 만장일치로 나가떨어지냐…….","JPN":"あれだけ騒いでおいて、満場一致で負けだなんて……","ENG":"How could you lose like that after all the commotion you stirred up?","TWN":"那些莫名其妙的講評，也可以當作是評審一致同意嗎……"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"할 수 없지. 잘 쳐 줘도 불판 위에서 몸부림치는 브로콜리 같았으니까.","JPN":"仕方ない。大目に見ても鉄板の上で転がるブロッコリーみたいだったから。","ENG":"It was inevitable. He looked like a twitching broccoli on a hot pan. And that's putting it gently.","TWN":"沒辦法，就算你跳得再好，人家畢竟有主場優勢。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"으윽, 누나에게 듣던 말이랑 똑같아…….","JPN":"ううっ、姉さんと同じこと言ってる……","ENG":"Ngh... That's exactly what my sister used to tell me...","TWN":"呃，姊姊好像也說過一模一樣的話……"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"하아. 어쩔 수 없군. 또 내가 나서야겠네.","JPN":"はあ。仕方ないな。またワタシの出番か。","ENG":"*Sigh* I guess there's no other option but for me to step up.","TWN":"哀哀，沒辦法，又只能我出馬囉。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"대체 뭘 어쩌려고?","JPN":"どうするつもりだよ？","ENG":"Huh? What are you going to do?","TWN":"你是想幹嘛啦？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"수아는 예전부터 몸치였던 걸로 기억하는데…….","JPN":"コトリちゃんて、昔からダンスが下手だった気がするけど……","ENG":"The Skia I remember had two left feet...","TWN":"我記得蘇亞從以前就肢體不協調欸……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"나는 예전의 내가 아니야.","JPN":"ワタシは昔のワタシじゃない。","ENG":"I'm not the same Skia you once knew.","TWN":"我已經不是以前的我。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"입 떡 벌어질 준비나 해. 로보팅의 새로운 아이콘 나가신다.","JPN":"驚く準備でもしてて。ロボットの新アイコンの登場だ。","ENG":"Get ready for your jaw to drop. A new robot dancer star will be born today.","TWN":"小心下巴脫臼，機械舞的新天后出場。"},"stage":{"bg":"HAVEN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"아니?! 이건……!","JPN":"何？！　これは……！","ENG":"What?! That's...!","TWN":"什麼？！這是……！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"여러 의미로 사람 같지 않은 춤이야.","JPN":"色んな意味で人間らしくないダンスだ。","ENG":"In a lot of ways, that dance was inhuman.","TWN":"這根本不是人類的舞蹈，有好多深層的含意。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"하지만 뻣뻣하기로 이 토미님을 따라오려면 한참 멀었다고 해야겠군.","JPN":"でも体のカクカク具合でこのトミー様を越えるには百年は早いな。","ENG":"I'll have to say that it'll be a while before you can rub shoulders with Tommy!","TWN":"不過肢體太過僵硬，跟湯米我比起來還差得遠呢！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"분명 가은이 추던 로봇 댄스야! 하트베리 팬이라면 점수를 더 줘야지!","JPN":"確かユキが踊ってたロボットダンスです！　ハートベリーのファンなら高い点数をあげないとなのです！","ENG":"That was certainly Gaeun's robot dance! I've got to give more points if you're a HRT Berry fan too!","TWN":"這很明顯是嘉恩跳過的機械舞欸！愛心莓果的粉絲是一定要加分的！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"장르가 너무 달라서 힘드네요. 제 취향에는…….","JPN":"ジャンルが違いすぎて難しいですね。私の好みには……","ENG":"Both dances were so different that it's hard for me to choose. But I think I like...","TWN":"好特別的舞風，有點難講評，不是我的菜……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"결과는 만장일치로, 허드슨 님의 승리입니다.","JPN":"結果は満場一致で、ハドソン様の勝利です。","ENG":"Again, Mr. Hudson wins with a unanimous vote!","TWN":"評審團一致同意，由哈德森先生勝出！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"쳇.","JPN":"ちっ。","ENG":"Tch.","TWN":"嘖。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"대단한 로봇 댄스였어. 허를 찔렸군.","JPN":"素晴らしいロボットダンスだったぞ。不意をつかれたな。","ENG":"That was an amazing robot dance. Quite the curveball, actually.","TWN":"很精彩的機械舞，令人瞠目結舌呢。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그럼 뭐 해. 당신의 느끼한 그루브에 져 버렸는데.","JPN":"なんの意味があるの。アナタのキモイグルーブに負けちゃったのに。","ENG":"Doesn't matter. I lost to your cheesy groove.","TWN":"有什麼用，還不是輸給你老派的律動。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"힘들게 살았나 보군. 인생은 승패로 모든 게 결정되지 않아.","JPN":"今まで苦労してきたんだな。人生は勝敗だけですべてが決まるわけではない。","ENG":"You must've lived a hard life. Not everything in life is determined by winning or losing.","TWN":"看來你的過去很辛苦呢，人生不是由勝負決定一切。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"얼마나 노력했고 얼마나 최선을 다했는지. 그 과정을 얼마나 즐겼는지가 중요하지.","JPN":"どれほど努力して、どれだけベストを尽くしたか。その過程をどれほど楽しんだのかが重要なんだぞ。","ENG":"It's about doing your best and how much effort you put in. What's important is how much you enjoy the journey.","TWN":"重點是你花多少心思，盡多少努力，過程中有多享受！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 형님께서 이 소중한 라스트 헤이븐을 맡기면서 해 주신 말씀이다.","JPN":"ヘイブン兄貴が、大切にしているこのラストヘイブンを任せてくれたときに言ってくれた言葉だ。","ENG":"This is what Mr. Haven said to me when he left me in charge of Last Haven.","TWN":"這是天堂大哥將這珍貴的最後的天堂交給我時所說的話。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"정말 헤이븐 형님이 한 말 맞아? 저런 꼰대 같은 말을 우리 형님이 하셨다고?","JPN":"本当にそれヘイブン兄貴の言葉なの？　そんなオヤジくさい話を、ヘイブン兄貴が？","ENG":"Are you sure that's what he said? That sounds like something a boomer would say!","TWN":"你確定是天堂大哥說的嗎？我們大哥會說那麼老掉牙的話嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"꼰대 같다니!","JPN":"オヤジくさいって！","ENG":"A boomer?!","TWN":"什麼老掉牙！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왜 네가 발끈하고 난리야?","JPN":"何でアンタが怒るんだよ？","ENG":"What are you getting all worked up for?","TWN":"你在激動什麼？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그거야…….","JPN":"そりゃあ……","ENG":"Well...","TWN":"因為……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"라스트 헤이븐도 그래.","JPN":"ラストヘイブンもそうだよ。","ENG":"Even Last Haven.","TWN":"最後的天堂也是，"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왜 피폐해진 사람들이 서로 속고 속이면서 돈에 목숨 거는 곳이 아닌 거지?","JPN":"疲弊した人たちが、お互い騙し合いながらお金に命をかけるところのはずなのに。","ENG":"Why isn't it a place where people lie and cheat each other for money?","TWN":"為何不是疲憊的人們彼此欺騙拿命賺錢的地方？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"대체 어디서 무슨 소릴 들은 거야?","JPN":"いったいどこで何を聞いたんだ？","ENG":"What are you talking about?","TWN":"這些你到底都哪聽來的？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"라스트 헤이븐은 그냥 남녀노소 누구나 즐길 수 있는 공간이야. 모○폴리 게임 못 봤어?","JPN":"ラストヘイブンは純粋に老若男女、誰でも楽しめる空間だよ。モ〇ポリーゲームあったの、見なかった？","ENG":"Last Haven is a place where anyone can enjoy themselves. Didn't you see the Molonopy board game?","TWN":"最後的天堂是男女老少都可以在這裡享樂的空間，你沒玩過大○翁嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러니까 더 이상하지! 다들 그렇게 말했었다고!","JPN":"だからなおさら変なんだよ！　みんなそう言ってたんだってば！","ENG":"That's why I'm saying it's weird! It's what everyone told me!","TWN":"這樣更奇怪吧！大家都這麼說欸！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이러는 동안 벌써 마지막 기회만 남아 버렸어. 어쩌지?","JPN":"そうこうしてる間にもう最後だよ。どうしよう？","ENG":"You know, we only have one chance left. What should we do?","TWN":"在你們爭執不休的同時，現在只剩下最後一次機會，怎麼辦呢？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"으으음…….","JPN":"う～ん……","ENG":"Hmm...","TWN":"嗯嗯嗯……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"시그마, 왜 그래? 무슨 고민 있어?","JPN":"シグマ、どうしたの？　何か悩みでもあるの？","ENG":"What's wrong, Sigma? What are you thinking about?","TWN":"西格瑪，你怎麼了？有什麼問題嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"심사위원들을 분석하는 중이야.","JPN":"審査員を分析してるところ。","ENG":"I'm trying to analyze the judges.","TWN":"我正在分析評審團。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그리고 알아낸 것 같아! 심사위원들이 공통적으로 보는 기준!","JPN":"それに、わかったかも！　審査員が見る共通の基準！","ENG":"And I think I found out something! About what they all commonly look for in dances!","TWN":"我發現囉！評審團的共同標準！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"정말? 그게 뭔데?","JPN":"本当？　何なの？","ENG":"Really? What is it?","TWN":"真的嗎？是什麼？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"비결은 바로 해파리야!","JPN":"答えはクラゲだよ！","ENG":"The secret is \\"jellyfish\\"!","TWN":"秘訣就是水母！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"해파리? 바다에 사는 그 해파리 말이야?","JPN":"クラゲ？　海に住んでるあのクラゲのこと？","ENG":"Jellyfish? You mean the creature that lives in the ocean?","TWN":"水母？你是說在海裡的水母嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 흐느적거리는 춤일수록 좋은 점수를 받을 거야!","JPN":"うん！　踊りのユラフワ度が高いほどいい点数をもらえるはず！","ENG":"Yes! The more I dance like a jellyfish, the more points I'll earn!","TWN":"沒錯！動作越像水母漂分數就會越高！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"확실한 거야? 그거라면 저 아저씨를 이길 수 있어?","JPN":"確かなの？　それならあのおじさんに勝てる？","ENG":"Are you sure about that? You think you can win, then?","TWN":"你認真的嗎？這樣就可以贏過大叔？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼. 심사위원들이 했던 말이랑 체온, 심박수, 그리고 음성 데이터까지 전~부 분석했는걸.","JPN":"もちろん。審査員が話したことと体温、心拍数、それに音声データまでぜ～んぶ分析したもん。","ENG":"Yup! I even analyzed their comments, body temperature, heart rate, and audio data.","TWN":"沒錯！這是我將評審團說過的話、體溫、脈搏和聲音，全～部分析後得到的結果喔！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"애초에 이런 방식의 게임에서 확실한 수를 계산한다는 게 말이 안 되지. 일반적이라면.","JPN":"だいたい、こういった方式のゲームで確実な数を計算するってことはあり得ない。一般的には。","ENG":"Normally, calculating the probabilities of these types of games is impossible.","TWN":"基本上這種遊戲本來就無法計算正確的數字。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시그마, 네 연산 능력은 대체 얼마나 좋은 거야?","JPN":"シグマの演算能力の高さっていったいどのくらいなの？","ENG":"Sigma, how good are your calculating abilities anyway?","TWN":"西格瑪，你的運算能力到底有多強？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"하늘만큼 땅만큼 아빠 사랑만큼!","JPN":"天くらい、地くらい、パパの愛くらい！","ENG":"As good as heaven and earth, and Daddy's love!","TWN":"像天、像地、像爸爸的愛那樣強！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……하나도 못 알아듣겠어.","JPN":"……さっぱりわからないよ。","ENG":"...I don't understand any of your words.","TWN":"……聽不懂你在說什麼。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이제 남은 건 나랑 글린다 정도네.","JPN":"それじゃ残ったのは私とグリンダくらいだな。","ENG":"The only ones remaining are Glinda and me.","TWN":"現在能上場的只剩我和格琳達吧？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"나는 보다시피 다리가 이래서 무리야. 기껏 춰도 심사위원들 눈에는 잘 보이지도 않을걸.","JPN":"私は見てのとおり足がこうだから無理。踊っても審査員の目に良くは映らないと思う。","ENG":"But as you can see, I can't dance with these legs. Even if I did, the judges wouldn't be able to see what I did.","TWN":"你看我的腳這樣，就算硬跳，也無法得到評審團的青睞的。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이제는 나더러 춤까지 추라고? 왜, 아예 함교를 점거하라고 하지?","JPN":"私に踊れって言ってる？　この際艦橋も占拠してあげようか？","ENG":"Oh, so now you want me to dance? Why not ask ME to take over the ship?","TWN":"現在是還要叫我跳舞嗎？是怎樣？乾脆叫我霸佔艦橋好啦！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"응? 리온, 어디 가? 거기는 무대 쪽인데?","JPN":"うん？　リオンどこ行くの？　そっちはステージだよ？","ENG":"Huh? Liona, where're you going? That's the stage.","TWN":"嗯？萊恩，你要去哪？那裡是舞台的方向欸？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"호오, 마지막 도전자는 가냘파 보이는 소녀로군.","JPN":"ほう、最後の挑戦者はか弱そうな少女か。","ENG":"Ho-oh... So my last challenger is a little lady.","TWN":"喔呵，最後一位挑戰者是柔弱少女嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"좋아. 하지만 그런 소심한 태도로 나에게 이길 수 있을까?","JPN":"いいだろう。だがそのようなおどおどした態度で俺に勝てるかな？","ENG":"Very well! Do you think you can win when you look so timid and scared?","TWN":"很好，但你用那副怯弱的態度有辦法贏過我嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"난…… 못 이겨.","JPN":"私……勝てないよ。","ENG":"I... can't beat you.","TWN":"我……贏不過你。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"흠. 처음부터 포기 상태라면 겨루는 재미가 없는데.","JPN":"ふむ。最初から諦めていると競い甲斐がないんだが。","ENG":"Hmm... But, it's no fun if you give up before we even start.","TWN":"哼，現在就不戰而降的話，那還有什麼好比的！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"하지만……","JPN":"でも……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"하지만 토토라면 이길 수 있어!!","JPN":"でも、トトなら勝てる！！","ENG":"But Toto can!!","TWN":"可是托托可以贏過你的！！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};